import { chromium } from 'playwright';

const url = process.argv[2] || 'http://localhost:3000/footy/player/1';
const widths = [1400, 900, 500];

const browser = await chromium.launch();
for (const width of widths) {
    const page = await browser.newPage({ viewport: { width, height: 1000 } });
    const errors = [];
    page.on('console', (msg) => {
        if (msg.type() === 'error') errors.push(msg.text());
    });
    await page.goto(url, { waitUntil: 'networkidle' });
    await page.waitForTimeout(500);
    const path = `/private/tmp/claude-501/-Volumes-Development-next-www-toastboy/a8978a5d-c16c-43d4-a25f-e0971fb04068/scratchpad/profile-${width}.png`;
    await page.screenshot({ path, fullPage: true });
    console.log(`Saved ${path}`);
    if (errors.length) console.log(`Console errors at ${width}px:`, errors);
    await page.close();
}
await browser.close();

